
const MS_DAY = 86400000, NHS_60_DAY = 60, NHS_30_DAY = 30;
const UPLOAD_KEY='rpeak_uploaded_rows_v1', UPLOAD_META_KEY='rpeak_uploaded_meta_v1';
const RAW = loadInitialRows();
function loadInitialRows(){try{let s=localStorage.getItem(UPLOAD_KEY); if(s) return JSON.parse(s)}catch(e){} return window.RPEAK_ROWS || []}
function currentDataMeta(){try{return JSON.parse(localStorage.getItem(UPLOAD_META_KEY)||'{}')}catch(e){return {}}}
function clearUploadedData(){localStorage.removeItem(UPLOAD_KEY); localStorage.removeItem(UPLOAD_META_KEY); location.reload()}
function normHeader(s){return String(s||'').toLowerCase().replace(/[^a-z0-9]+/g,' ').trim()}
const FIELD_HINTS={
 'Project Code':['project code','project id','project','study code','study id','short title','trial id','irás id','iras id'],
 'Project Status':['project status','study status','status'],
 'Task Name':['task name','task','activity','milestone','step','item'],
 'Task Comment':['task comment','comment','comments','notes','description','detail','response','delay reason'],
 'Target Days to complete':['target days to complete','target days','target','sla','planned days','threshold','due in days'],
 'Date Created':['date created','created date','created','opened','task created','creation date'],
 'Start Date':['start date','started','clock start','hra approval','site selected','date site selected','trust selected','date trust invited','setup start'],
 'Due Date':['due date','deadline','target date','planned completion','due'],
 'Completion Date':['completion date','completed date','completed','finish date','actual completion','closed date'],
 'On time or Late':['on time or late','timing','late','on time','performance'],
 'Days to completion':['days to completion','completion days','days complete','elapsed days','duration'],
 'Days active (if not complete)':['days active if not complete','days active','active days','age','open days','days open'],
 'Task Status':['task status','status','task state','state']
};
function bestColumn(headers, hints){let norm=headers.map(h=>[h,normHeader(h)]); let best='', score=0; for(let [h,nh] of norm){for(let term of hints){let nt=normHeader(term); let s=0; if(nh===nt) s=10; else if(nh.includes(nt)||nt.includes(nh)) s=5; else {let words=nt.split(' ').filter(w=>w.length>2); if(words.length && words.every(w=>nh.includes(w))) s=3} if(s>score){score=s; best=h}}} return score?best:''}
function parseNumberishDate(v){if(v instanceof Date && !isNaN(v)) return v; if(v==null||v==='') return null; let n=num(v); if(n!==null && n>20000) return new Date(Date.UTC(1899,11,30)+Math.floor(n)*MS_DAY); let t=Date.parse(String(v)); return Number.isFinite(t)?new Date(t):null}
function toExcelSerial(d){return d?String(Math.floor((Date.UTC(d.getUTCFullYear(),d.getUTCMonth(),d.getUTCDate())-Date.UTC(1899,11,30))/MS_DAY)):''}
function chooseRelevantSheet(workbook){let best={name:workbook.SheetNames[0], rows:[], score:-1}; for(let name of workbook.SheetNames){let rows=XLSX.utils.sheet_to_json(workbook.Sheets[name],{defval:'',raw:false}); if(!rows.length) continue; let headers=Object.keys(rows[0]||{}); let score=0; for(let hints of Object.values(FIELD_HINTS)){if(bestColumn(headers,hints)) score++} score += Math.min(rows.length/1000,3); if(score>best.score) best={name,rows,score}} return best}
function normaliseUploadedRows(inputRows){let headers=Object.keys(inputRows[0]||{}); let map={}; for(let [field,hints] of Object.entries(FIELD_HINTS)) map[field]=bestColumn(headers,hints); let out=inputRows.map((r,i)=>{let o={}; for(let field of Object.keys(FIELD_HINTS)) o[field]=map[field]?String(r[map[field]]??''):''; if(!o['Project Code']) o['Project Code']=String(r[map['Project Code']]||r.Project||r.project||`Project ${i+1}`); if(!o['Task Name']) o['Task Name']=String(r[map['Task Name']]||r.Task||r.task||r.Activity||'Task'); let created=parseNumberishDate(o['Date Created']), start=parseNumberishDate(o['Start Date'])||created, due=parseNumberishDate(o['Due Date']), done=parseNumberishDate(o['Completion Date']); o['Date Created']=toExcelSerial(created); o['Start Date']=toExcelSerial(start); o['Due Date']=toExcelSerial(due); o['Completion Date']=toExcelSerial(done); let target=num(o['Target Days to complete']); if(target===null){let task=(o['Task Name']||'').toLowerCase(); target=task.includes('first patient')||task.includes('1st patient')?30:task.includes('green light')||task.includes('siv')?14:task.includes('local information')?0:7; o['Target Days to complete']=String(target)} let completed=!!done || /complete|closed|done/i.test(o['Task Status']); if(!o['Task Status']) o['Task Status']=completed?'Complete':'Active'; if(!o['Days to completion'] && done && (start||created)) o['Days to completion']=String(Math.max(0,Math.round((done-(start||created))/MS_DAY))); if(!o['Days active (if not complete)'] && !completed && (start||created)) o['Days active (if not complete)']=String(Math.max(0,Math.round((new Date()-(start||created))/MS_DAY))); if(!o['On time or Late']){let elapsed=num(completed?o['Days to completion']:o['Days active (if not complete)']); o['On time or Late']=completed?(Number.isFinite(elapsed)&&Number.isFinite(target)&&elapsed<=target?'On Time':'Late'):''} return o}).filter(r=>r['Project Code']||r['Task Name']); return {rows:out,map}}
async function handleUpload(ev){let file=ev.target.files?.[0]; if(!file) return; let status=document.getElementById('uploadStatus'); try{if(status) status.textContent='Reading file…'; let buf=await file.arrayBuffer(); let wb=XLSX.read(buf,{type:'array',cellDates:true}); let chosen=chooseRelevantSheet(wb); if(!chosen.rows.length) throw new Error('No tabular rows found'); let normalised=normaliseUploadedRows(chosen.rows); localStorage.setItem(UPLOAD_KEY,JSON.stringify(normalised.rows)); localStorage.setItem(UPLOAD_META_KEY,JSON.stringify({uploaded:true,name:file.name,sheet:chosen.name,nRows:normalised.rows.length,note:`Mapped ${Object.values(normalised.map).filter(Boolean).length} fields from sheet ${chosen.name}`})); location.reload()}catch(e){if(status) status.textContent=`Could not import file: ${e.message}`; console.error(e)}}

function num(x){let n=parseFloat(x); return Number.isFinite(n)?n:null}
function excelDate(x){if(x instanceof Date && !isNaN(x)) return x; if(x==null||x==='') return null; let n=num(x); if(n!==null && n>20000) return new Date(Date.UTC(1899,11,30)+Math.floor(n)*MS_DAY); let t=Date.parse(String(x)); return Number.isFinite(t)?new Date(t):null}
function fmtDate(d){return d?d.toISOString().slice(0,10):''}
function median(a){a=a.filter(Number.isFinite).sort((a,b)=>a-b); if(!a.length)return null; let m=Math.floor(a.length/2); return a.length%2?a[m]:(a[m-1]+a[m])/2}
function mean(a){a=a.filter(Number.isFinite); return a.length?a.reduce((s,x)=>s+x,0)/a.length:null}
function pct(n,d){return d?Math.round(1000*n/d)/10:0}
function esc(s){return String(s ?? '').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function normTask(s){return (s||'').trim().replace(/\s+/g,' ')}
function daysLate(r){if(r.taskStatus==='Complete') return Math.max(0,(r.daysToCompletion??0)-(r.targetDays??0)); if(r.dueDate && r.isOpen) return Math.max(0,Math.floor((new Date()-r.dueDate)/MS_DAY)); return 0}
function nhsBandDays(days){if(!Number.isFinite(days))return 'No date'; if(days>NHS_60_DAY)return '>60 days'; if(days>NHS_30_DAY)return '31–60 days'; return '≤30 days'}
function nhsBadgeDays(days){let b=nhsBandDays(days); let cls=b==='>60 days'?'nhs60':b==='31–60 days'?'nhs30':'nhsok'; return `<span class="badge ${cls}">${b}</span>`}
const CATEGORY_RULES=[
 ['Finance review',['finance review','financial management','cpms','cost code','costing','soecat','cost split','cost attribution']],
 ['Set-up fees / invoicing',['set up reconciliation','reconciliation tracker','invoice','invoicing','setup fees','set-up fees']],
 ['Local Information Pack / documents',['local information pack',' lip ','provide the local information pack','document pack','hra approval','iras','oid','pis/icf','protocol']],
 ['Trust invited / selected',['trust invited','trust selected','site invited','site selected','date trust invited','date site invited']],
 ['Green light to recruit',['green light','recruitment can commence']],
 ['First patient / recruitment',['1st patient','first patient','patient recruited','delay reasons']],
 ['Recruitment plan',['recruitment plan','retention plan']],
 ['SIV / site initiation',['siv','site initiation']],
 ['Clinical Director notification',['clinical director notification','send notification to the clinical director','receipt of clinical director']],
 ['Risk assessment / planning',['risk assessment','planning review','2nd risk assessment']],
 ['Service support implications',['service support','nhs support costs','lcrn resource']],
 ['Pharmacy',['pharmacy','drug storage','pharmacy manual','drug package']],
 ['Labs / biospecimen / RIBS',['ribs','biospecimen','biobank','mcrf','labs','laboratory']],
 ['Imaging',['imaging','ophthalmic imaging','access imaging']],
 ['Hive / EHR build',['hive','ehr','build request','researchcontent']],
 ['Feasibility / capacity',['feasibility','capacity and capability','capacity & capability']],
 ['Contracts / agreements',['contract','agreement','model agreement','legal']],
 ['Sponsorship / sponsor liaison',['sponsor','sponsor email','sponsor authorisation']],
 ['Governance / approvals',['hra','approval','regulatory','amendment','ethics']],
 ['Data / systems / access',['data','database','access','account','log in','system']],
 ['Training / delegation',['training','delegation log','gcp','site file']],
 ['PIC / non-recruiting handling',['pic','participant identification centre','non-recruiting']],
 ['Monitoring / follow-up',['follow up','monitoring','review','tracker']],
 ['Other / uncategorised',[]]
];
function categoryFor(r){let text=((r.task||'')+' '+(r.taskComment||'')).toLowerCase().replace(/[^a-z0-9/]+/g,' '); let best='Other / uncategorised', bestScore=0; CATEGORY_RULES.forEach(([cat,terms])=>{let score=0; terms.forEach(term=>{let t=term.toLowerCase().trim(); if(!t)return; if(text.includes(t)) score+=t.length>12?4:2; else {let words=t.split(/\s+/).filter(w=>w.length>3); if(words.length && words.every(w=>text.includes(w))) score+=1.5}}); if(score>bestScore){bestScore=score;best=cat}}); return best}
const rows=RAW.map((r,i)=>{let o={...r,_i:i}; o.project=(r['Project Code']||'').trim(); o.projectStatus=(r['Project Status']||'').trim()||'Unknown'; o.task=normTask(r['Task Name']); o.taskComment=r['Task Comment']||''; o.targetDays=num(r['Target Days to complete']); o.createdDate=excelDate(r['Date Created']); o.startDate=excelDate(r['Start Date']); o.dueDate=excelDate(r['Due Date']); o.completionDate=excelDate(r['Completion Date']); o.timing=(r['On time or Late']||'').trim(); o.daysToCompletion=num(r['Days to completion']); o.daysActive=num(r['Days active (if not complete)']); o.taskStatus=(r['Task Status']||'').trim()||'Unknown'; o.isOpen=o.taskStatus!=='Complete'; o.taskEndDate=o.completionDate||o.dueDate||o.startDate||o.createdDate; o.taskDuration=daysBetween(o.startDate,o.completionDate); o.elapsed=o.isOpen?o.daysActive:(Number.isFinite(o.taskDuration)?o.taskDuration:o.daysToCompletion); o.lateDays=daysLate(o); o.overTarget=Number.isFinite(o.elapsed)&&Number.isFinite(o.targetDays)?Math.max(0,o.elapsed-o.targetDays):0; o.category=categoryFor(o); o.nhsBand=nhsBandDays(o.elapsed); return o});
const projects=[...new Set(rows.map(r=>r.project).filter(Boolean))].sort();
function group(arr,key){const m=new Map(); arr.forEach(x=>{let k=typeof key==='function'?key(x):x[key]; if(!m.has(k))m.set(k,[]); m.get(k).push(x)}); return m}
function riskClass(b){return b==='Critical'?'risk-critical':b==='High'?'risk-high':b==='Moderate'?'risk-mid':'risk-low'}
function timingBadge(t){if(t==='Late')return '<span class="badge late">Late</span>'; if(t==='On Time')return '<span class="badge ontime">On time</span>'; return '<span class="badge activeb">Active/Pending</span>'}
function lastDateOf(r){return r.completionDate || r.dueDate || r.startDate || r.createdDate}
function setupStart(rs){let dates=rs.map(r=>r.startDate||r.createdDate).filter(Boolean); return dates.length?new Date(Math.min(...dates.map(d=>+d))):null}
function setupEnd(rs){let dates=rs.map(lastDateOf).filter(Boolean); return dates.length?new Date(Math.max(...dates.map(d=>+d))):null}
function greenLightRow(rs){return rs.filter(r=>/green light/i.test(r.task)).sort((a,b)=>+(a.completionDate||a.dueDate||a.startDate||0)-+(b.completionDate||b.dueDate||b.startDate||0)).slice(-1)[0]||null}
function firstPatientRow(rs){return rs.filter(r=>/1st patient|first patient|patient recruited/i.test(r.task)).sort((a,b)=>+(a.completionDate||a.dueDate||a.startDate||0)-+(b.completionDate||b.dueDate||b.startDate||0)).slice(-1)[0]||null}
function daysBetween(a,b){return a&&b?Math.round((b-a)/MS_DAY):null}
function projectAgg(){return [...group(rows,'project')].map(([project,rs])=>{let active=rs.filter(r=>r.isOpen), comp=rs.filter(r=>r.taskStatus==='Complete'), late=comp.filter(r=>r.timing==='Late'), over60=active.filter(r=>(r.daysActive||0)>60), over30=active.filter(r=>(r.daysActive||0)>30), elapsed=rs.map(r=>r.elapsed).filter(Number.isFinite), activeAge=active.map(r=>r.daysActive).filter(Number.isFinite), overdue=active.filter(r=>r.lateDays>0); let start=setupStart(rs), end=setupEnd(rs), gl=greenLightRow(rs), fp=firstPatientRow(rs), greenDate=gl?(gl.completionDate||gl.dueDate||null):null, fpDate=fp?(fp.completionDate||fp.dueDate||null):null, setupDays=daysBetween(start,end), startToGreen=daysBetween(start,greenDate), greenToFirst=daysBetween(greenDate,fpDate); let missSetup=Number.isFinite(startToGreen)?startToGreen>60:false, missFirst=Number.isFinite(greenToFirst)?greenToFirst>30:false; let score=overdue.length*7 + over60.length*12 + over30.length*4 + active.reduce((s,r)=>s+(r.overTarget||0),0) + late.length*1.5 + (mean(elapsed)||0)*0.15 + (missSetup?30:0) + (missFirst?20:0); let band=score>140?'Critical':score>60?'High':score>20?'Moderate':'Low'; return {project,projectStatus:rs[0].projectStatus,n:rs.length,complete:comp.length,active:active.length,pending:rs.filter(r=>r.taskStatus==='Pending').length,late:late.length,lateRate:pct(late.length,comp.length||rs.length),medianDays:median(elapsed),meanDays:mean(elapsed),maxActive:activeAge.length?Math.max(...activeAge):0,overdue:overdue.length,over30:over30.length,over60:over60.length,setupStart:start,setupEnd:end,setupDays,startToGreen,greenToFirst,missSetup,missFirst,greenLightTask:gl,firstPatientTask:fp,riskScore:Math.round(score),riskBand:band,tasks:rs}}).sort((a,b)=>b.riskScore-a.riskScore)}
const pAgg=projectAgg();
function taskAgg(){return [...group(rows,'task')].map(([task,rs])=>{let comp=rs.filter(r=>r.taskStatus==='Complete'), active=rs.filter(r=>r.isOpen), durations=comp.map(r=>r.taskDuration).filter(Number.isFinite), activeAge=active.map(r=>r.daysActive||0), overdue=active.filter(r=>r.lateDays>0), over60=active.filter(r=>(r.daysActive||0)>60); return {task,n:rs.length,projects:new Set(rs.map(r=>r.project)).size,complete:comp.length,active:active.length,medianDuration:median(durations),meanDuration:mean(durations),medianDays:median(durations),meanDays:mean(durations),maxActive:activeAge.reduce((a,b)=>Math.max(a,b),0),overdue:overdue.length,over60:over60.length,bottleneckScore:Math.round((mean(durations)||0)+overdue.length*9+over60.length*12+active.length*2),rows:rs}}).sort((a,b)=>b.bottleneckScore-a.bottleneckScore)}
const tAgg=taskAgg();
function categoryAgg(){return [...group(rows,'category')].map(([category,rs])=>{let comp=rs.filter(r=>r.taskStatus==='Complete'), active=rs.filter(r=>r.isOpen), durations=comp.map(r=>r.taskDuration).filter(Number.isFinite), overdue=active.filter(r=>r.lateDays>0), over60=active.filter(r=>(r.daysActive||0)>60), projectSet=new Set(rs.map(r=>r.project)); let missedSetupProjects=[...projectSet].filter(p=>pAgg.find(x=>x.project===p)?.missSetup).length, missedFirstProjects=[...projectSet].filter(p=>pAgg.find(x=>x.project===p)?.missFirst).length; return {category,n:rs.length,projects:projectSet.size,complete:comp.length,active:active.length,late:0,lateRate:0,medianDays:median(durations),meanDays:mean(durations),medianDelay:median(durations)||0,meanDelay:mean(durations)||0,overdue:overdue.length,over60:over60.length,missedSetupProjects,missedFirstProjects,bottleneckScore:Math.round((mean(durations)||0)+overdue.length*8+over60.length*12+active.length*2+missedSetupProjects*4+missedFirstProjects*3),rows:rs}}).sort((a,b)=>b.bottleneckScore-a.bottleneckScore)}
const cAgg=categoryAgg();
const sortState={};
function cellValue(r,c){let v=c.sort?c.sort(r):(c.key?r[c.key]:(c.f?c.f(r):'')); if(v==null)return ''; return v}
function renderTable(id,cols,data,limit=700){const el=document.getElementById(id); let st=sortState[id]; let arr=[...data]; if(st){let c=cols[st.i]; arr.sort((a,b)=>{let av=cellValue(a,c), bv=cellValue(b,c), an=parseFloat(av), bn=parseFloat(bv); let res=(Number.isFinite(an)&&Number.isFinite(bn))?an-bn:String(av).localeCompare(String(bv),undefined,{numeric:true,sensitivity:'base'}); return st.dir==='asc'?res:-res})} el.innerHTML='<thead><tr>'+cols.map((c,i)=>`<th data-i="${i}" class="${st&&st.i===i?'sort-'+st.dir:''}">${esc(c.label)}</th>`).join('')+'</tr></thead><tbody>'+arr.slice(0,limit).map(r=>'<tr>'+cols.map(c=>`<td>${c.f?c.f(r):esc(r[c.key]??'')}</td>`).join('')+'</tr>').join('')+'</tbody>'; el.querySelectorAll('th').forEach(th=>th.onclick=()=>{let i=+th.dataset.i; sortState[id]=sortState[id]&&sortState[id].i===i?{i,dir:sortState[id].dir==='asc'?'desc':'asc'}:{i,dir:'asc'}; renderTable(id,cols,data,limit)})}
function barLabels(a,n=44){return a.map(s=>String(s).length>n?String(s).slice(0,n-1)+'…':String(s))}
function plot(id,data,layout){Plotly.newPlot(id,data,{paper_bgcolor:'rgba(0,0,0,0)',plot_bgcolor:'rgba(0,0,0,0)',font:{color:'#172033'},margin:{l:210,r:30,t:55,b:85},yaxis:{automargin:true,gridcolor:'#e5e7eb'},xaxis:{automargin:true,gridcolor:'#e5e7eb'},...layout},{responsive:true,displayModeBar:false})}

let activeModalPlotKind=null;
function projectStatusGroup(p){let s=String(p.projectStatus||'Unknown').trim(); if(!s) return 'Unknown'; if(s.toLowerCase()==='open') return 'Open'; if(s.toLowerCase()==='pending') return 'Pending'; if(s.toLowerCase().includes('setup')||s.toLowerCase().includes('set-up')) return 'In setup'; return s}
function projectStatusOptions(){let statuses=[...new Set(pAgg.map(projectStatusGroup))].sort((a,b)=>a.localeCompare(b)); return statuses}
function filteredProjectsForModal(){let v=document.getElementById('modalStatusFilter')?.value||''; return pAgg.filter(p=>!v||projectStatusGroup(p)===v)}
function setupPlotData(expanded=false, source=pAgg){let all=source.filter(p=>Number.isFinite(p.startToGreen)).sort((a,b)=>b.startToGreen-a.startToGreen); return (expanded?all:all.slice(0,22)).reverse()}
function recruitPlotData(expanded=false, source=pAgg){let all=source.filter(p=>Number.isFinite(p.greenToFirst)).sort((a,b)=>b.greenToFirst-a.greenToFirst); return (expanded?all:all.slice(0,22)).reverse()}
function setupPlotTrace(data){return [{type:'bar',orientation:'h',y:data.map(p=>p.project),x:data.map(p=>p.startToGreen),marker:{color:data.map(p=>p.startToGreen>60?'#dc2626':'#15803d')},text:data.map(p=>p.startToGreen>60?'>60 days':'≤60 days'),hovertemplate:'%{y}<br>Start to green light: %{x} days<extra></extra>'}]}
function recruitPlotTrace(data){return [{type:'bar',orientation:'h',y:data.map(p=>p.project),x:data.map(p=>p.greenToFirst),marker:{color:data.map(p=>p.greenToFirst>30?'#dc2626':'#15803d')},text:data.map(p=>p.greenToFirst>30?'>30 days':'≤30 days'),hovertemplate:'%{y}<br>Green light to first patient: %{x} days<extra></extra>'}]}
function setupLayout(data){return {title:'Projects: setup target, start → green light',xaxis:{title:'days',range:[0,Math.max(70,...data.map(p=>p.startToGreen||0))*1.05]},shapes:[{type:'line',x0:60,x1:60,y0:-0.5,y1:data.length-0.5,line:{color:'#991b1b',dash:'dash'}}],annotations:[{x:60,y:data.length-0.2,text:'60-day target',showarrow:false,xanchor:'left',font:{color:'#991b1b'}}]}}
function recruitLayout(data){return {title:'Projects: recruitment target, green light → first patient',xaxis:{title:'days',range:[0,Math.max(40,...data.map(p=>p.greenToFirst||0))*1.05]},shapes:[{type:'line',x0:30,x1:30,y0:-0.5,y1:data.length-0.5,line:{color:'#991b1b',dash:'dash'}}],annotations:[{x:30,y:data.length-0.2,text:'30-day target',showarrow:false,xanchor:'left',font:{color:'#991b1b'}}]}}
function drawSetupPlots(){let setupData=setupPlotData(false); plot('setupDurationPlot',setupPlotTrace(setupData),setupLayout(setupData)); let recruitData=recruitPlotData(false); plot('greenLightPlot',recruitPlotTrace(recruitData),recruitLayout(recruitData))}
function populateModalStatusFilter(){let sel=document.getElementById('modalStatusFilter'); if(!sel) return; let current=sel.value; sel.innerHTML='<option value="">All statuses</option>'+projectStatusOptions().map(s=>`<option value="${esc(s)}">${esc(s)}</option>`).join(''); if([...sel.options].some(o=>o.value===current)) sel.value=current}
function openPlotModal(kind){let modal=document.getElementById('plotModal'), plotEl=document.getElementById('modalPlot'); if(!modal||!plotEl) return; activeModalPlotKind=kind; populateModalStatusFilter(); modal.classList.add('active'); setTimeout(redrawModalPlot,50)}
function redrawModalPlot(){let title=document.getElementById('modalTitle'); if(!activeModalPlotKind||!title) return; let status=document.getElementById('modalStatusFilter')?.value||'', source=filteredProjectsForModal(), suffix=status?` (${status})`:''; if(activeModalPlotKind==='setup'){let data=setupPlotData(true,source); title.textContent='All studies: setup target, start → green light'+suffix; plot('modalPlot',setupPlotTrace(data),{...setupLayout(data),height:Math.max(560,90+data.length*20),margin:{l:170,r:40,t:60,b:70}})} else {let data=recruitPlotData(true,source); title.textContent='All studies: recruitment target, green light → first patient'+suffix; plot('modalPlot',recruitPlotTrace(data),{...recruitLayout(data),height:Math.max(560,90+data.length*20),margin:{l:170,r:40,t:60,b:70}})}}
function closePlotModal(){let modal=document.getElementById('plotModal'); if(modal) modal.classList.remove('active'); activeModalPlotKind=null}
document.addEventListener('keydown',e=>{if(e.key==='Escape') closePlotModal()});

function statusSplitMetrics(){let groups=[{status:'Open',match:s=>String(s).toLowerCase()==='open'},{status:'Non-Open',match:s=>String(s).toLowerCase()!=='open'}]; return groups.map(g=>{let ps=pAgg.filter(p=>g.match(p.projectStatus)); let trs=rows.filter(r=>g.match(r.projectStatus)); let completed=trs.filter(r=>r.taskStatus==='Complete'), durations=completed.map(r=>r.taskDuration).filter(Number.isFinite), active=trs.filter(r=>r.isOpen), setup=ps.map(p=>p.startToGreen).filter(Number.isFinite), recruit=ps.map(p=>p.greenToFirst).filter(Number.isFinite); return {status:g.status,projects:ps.length,tasks:trs.length,active:active.length,completed:completed.length,medianDuration:median(durations),meanDuration:mean(durations),medianSetup:median(setup),medianRecruit:median(recruit),oldestActive:active.map(r=>r.daysActive||0).reduce((a,b)=>Math.max(a,b),0)}})}
function renderStatusSplit(){let el=document.getElementById('statusSplit'); if(!el)return; el.innerHTML=statusSplitMetrics().map(m=>`<div class="card"><h4>${esc(m.status)}</h4><div class="pillrow"><span class="metric"><b>${m.projects}</b><br>Projects</span><span class="metric"><b>${m.tasks}</b><br>Tasks</span><span class="metric"><b>${m.active}</b><br>Active tasks</span><span class="metric"><b>${m.medianDuration??'–'} days</b><br>Median task completion</span><span class="metric"><b>${m.medianSetup??'–'} days</b><br>Median start→green</span><span class="metric"><b>${m.oldestActive} days</b><br>Oldest active task</span></div><p class="small">Completion duration uses task Start Date → Completion Date where both are available; active-task age is shown separately rather than treated as completion time.</p></div>`).join('')}
function ganttRows(rs){return rs.filter(r=>r.startDate && r.taskEndDate).sort((a,b)=>a.startDate-b.startDate || String(a.task).localeCompare(String(b.task)))}
function drawProjectGantt(id,rs){let gr=ganttRows(rs); if(!gr.length){document.getElementById(id).innerHTML='<p class="small">No task rows have enough start/end date information for a Gantt view.</p>'; return} let base=gr.map(r=>r.startDate), x=gr.map(r=>Math.max(1,Math.round((r.taskEndDate-r.startDate)/MS_DAY))), y=gr.map(r=>barLabels([r.task],46)[0]), custom=gr.map(r=>[r.project,fmtDate(r.startDate),fmtDate(r.completionDate),r.taskStatus,Number.isFinite(r.taskDuration)?r.taskDuration:null,r.daysActive]); plot(id,[{type:'bar',orientation:'h',base:base,x:x,y:y,customdata:custom,marker:{color:gr.map(r=>r.taskStatus==='Complete'?'#15803d':'#b45309')},hovertemplate:'%{y}<br>Start: %{customdata[1]}<br>Completed: %{customdata[2]}<br>Status: %{customdata[3]}<br>Completion duration: %{customdata[4]} days<extra></extra>'}],{title:'Project task timeline (Start Date → Completion Date / current task end)',barmode:'stack',xaxis:{type:'date',title:'calendar date'},yaxis:{automargin:true},margin:{l:220,r:30,t:55,b:70},height:Math.max(360,120+gr.length*28)})}

function initOverview(){let complete=rows.filter(r=>r.taskStatus==='Complete'), active=rows.filter(r=>r.isOpen), late=complete.filter(r=>r.timing==='Late'), overdue=active.filter(r=>r.lateDays>0), over30=active.filter(r=>(r.daysActive||0)>30), over60=active.filter(r=>(r.daysActive||0)>60), setupVals=pAgg.map(p=>p.setupDays).filter(Number.isFinite), greenVals=pAgg.map(p=>p.startToGreen).filter(Number.isFinite), missedSetup=pAgg.filter(p=>p.missSetup), gtFirstVals=pAgg.map(p=>p.greenToFirst).filter(Number.isFinite), missedFirst=pAgg.filter(p=>p.missFirst); let setupHit=greenVals.length-missedSetup.length, firstHit=gtFirstVals.length-missedFirst.length; let k=[['Projects',projects.length,'unique project codes'],['Median setup',`${median(setupVals)??'–'} days`,'first to last task date per project'],['Start→green light target',`${pct(setupHit,greenVals.length)}%`,`${setupHit}/${greenVals.length} projects ≤60 days · median ${median(greenVals)??'–'} days`],['Green→1st patient target',`${pct(firstHit,gtFirstVals.length)}%`,`${firstHit}/${gtFirstVals.length} projects ≤30 days · median ${median(gtFirstVals)??'–'} days`],['Active/Pending',active.length,`${overdue.length} overdue by due date`],['Completed late',`${pct(late.length,complete.length)}%`,`${late.length}/${complete.length} completed tasks`]]; document.getElementById('kpis').innerHTML=k.map(x=>`<div class="card kpi"><div class="label">${esc(x[0])}</div><div class="value">${esc(x[1])}</div><div class="note">${esc(x[2])}</div></div>`).join(''); document.getElementById('nhsContext').innerHTML=`<h3>150-day clinical trial target</h3><p class="small">Operational interpretation from your guidance: setup target is <b>60 days</b>. Clock starts at HRA approval for MFT-sponsored studies, or when sponsor information transfer permits MFT setup to begin for non-MFT-sponsored studies; in this extract the first task/start timestamp is used as a pragmatic proxy. Clock stops at <b>green light</b>. The <b>30-day</b> target is green light to first consent/recruit. Current active signal: <b>${over30.length}</b> active tasks are >30 days old; <b>${over60.length}</b> are >60 days old.</p>`; renderStatusSplit(); drawSetupPlots(); let top=pAgg.slice(0,15).reverse(); plot('topRiskPlot',[{type:'bar',orientation:'h',y:top.map(p=>p.project),x:top.map(p=>p.riskScore),text:top.map(p=>p.riskBand),marker:{color:top.map(p=>p.riskBand==='Critical'?'#7f1d1d':p.riskBand==='High'?'#dc2626':p.riskBand==='Moderate'?'#b45309':'#15803d')}}],{title:'Highest-risk projects',xaxis:{title:'risk score'}}); let byMonth=[...group(complete,r=>r.completionDate?fmtDate(r.completionDate).slice(0,7):'Unknown')].filter(x=>x[0]!=='Unknown').sort(); plot('timelinePlot',[{type:'scatter',mode:'lines+markers',x:byMonth.map(x=>x[0]),y:byMonth.map(x=>x[1].length),name:'completed'},{type:'scatter',mode:'lines+markers',x:byMonth.map(x=>x[0]),y:byMonth.map(x=>x[1].filter(r=>r.timing==='Late').length),name:'late completed'}],{title:'Completion volume over time',yaxis:{title:'tasks'}}); document.getElementById('insights').innerHTML=[`Median project setup duration is <b>${median(setupVals)??'–'} days</b> using first-to-last task date per project.`,`Median start/HRA proxy to green light is <b>${median(greenVals)??'–'} days</b>; <b>${missedSetup.length}/${greenVals.length}</b> projects exceed the 60-day setup target.`,`Median green light to first patient/consent is <b>${median(gtFirstVals)??'–'} days</b>; <b>${missedFirst.length}/${gtFirstVals.length}</b> projects exceed the 30-day recruitment target.`,`Resource-focus categories: <b>${cAgg.slice(0,5).map(c=>esc(c.category)).join('</b>, <b>')}</b>.`,`There are <b>${active.length}</b> active/pending task records; <b>${over60.length}</b> are beyond 60 days active.`].map(s=>`<li>${s}</li>`).join('')}
function initProjects(){document.getElementById('projectStatusFilter').innerHTML += [...new Set(pAgg.map(p=>p.projectStatus))].sort().map(s=>`<option>${esc(s)}</option>`).join(''); plot('projectScatter',[{type:'scatter',mode:'markers',x:pAgg.map(p=>p.lateRate),y:pAgg.map(p=>p.maxActive),text:pAgg.map(p=>p.project),customdata:pAgg.map(p=>p.project),marker:{size:pAgg.map(p=>Math.max(8,Math.min(36,p.n/2))),color:pAgg.map(p=>p.riskScore),colorscale:'YlOrRd',reversescale:true,showscale:true,colorbar:{title:'risk'}}}],{title:'Project risk map',xaxis:{title:'completed late rate (%)'},yaxis:{title:'oldest active task (days)'}}); document.getElementById('projectScatter').on('plotly_click',e=>showProject(e.points[0].customdata)); ['projectSearch','projectStatusFilter','projectRiskFilter'].forEach(id=>document.getElementById(id).addEventListener('input',renderProjects)); renderProjects()}
function renderProjects(){let q=document.getElementById('projectSearch').value.toLowerCase(), st=document.getElementById('projectStatusFilter').value, rb=document.getElementById('projectRiskFilter').value; let data=pAgg.filter(p=>(!q||(p.project+' '+p.projectStatus).toLowerCase().includes(q))&&(!st||p.projectStatus===st)&&(!rb||p.riskBand===rb)); renderTable('projectTable',[{label:'Project',f:p=>`<a href="#" onclick="showProject('${esc(p.project)}');return false">${esc(p.project)}</a>`,sort:p=>p.project},{label:'Status',key:'projectStatus'},{label:'Risk',f:p=>`<span class="badge ${riskClass(p.riskBand)}">${p.riskBand}</span>`,sort:p=>p.riskScore},{label:'Tasks',key:'n'},{label:'Active',key:'active'},{label:'Setup days',f:p=>Number.isFinite(p.setupDays)?p.setupDays+' days':'',sort:p=>p.setupDays??-1},{label:'Start→green',f:p=>Number.isFinite(p.startToGreen)?`<span class="badge ${p.startToGreen>60?'late':'ontime'}">${p.startToGreen} days</span>`:'',sort:p=>p.startToGreen??-1},{label:'Green→1st patient',f:p=>Number.isFinite(p.greenToFirst)?`<span class="badge ${p.greenToFirst>30?'late':'ontime'}">${p.greenToFirst} days</span>`:'',sort:p=>p.greenToFirst??-1},{label:'>60 days active',key:'over60'},{label:'Late rate',f:p=>p.lateRate+'%',sort:p=>p.lateRate},{label:'Oldest active',f:p=>p.maxActive+' days',sort:p=>p.maxActive}],data,1200)}
window.showProject=function(code){let p=pAgg.find(x=>x.project===code); if(!p)return; let rs=p.tasks.slice().sort((a,b)=>(a.startDate||0)-(b.startDate||0)||((b.taskDuration||0)-(a.taskDuration||0))); let completedDurations=rs.filter(r=>r.taskStatus==='Complete').map(r=>r.taskDuration).filter(Number.isFinite); document.getElementById('projectDetail').innerHTML=`<h3>${esc(p.project)}</h3><div class="pillrow"><span class="metric"><b>${esc(p.projectStatus)}</b><br>Status</span><span class="metric"><b>${p.riskBand}</b><br>Risk</span><span class="metric"><b>${p.n}</b><br>Tasks</span><span class="metric"><b>${p.active}</b><br>Active</span><span class="metric"><b>${median(completedDurations)??'–'} days</b><br>Median task completion</span><span class="metric"><b>${Number.isFinite(p.setupDays)?p.setupDays+' days':'–'}</b><br>Setup span</span><span class="metric"><b>${Number.isFinite(p.startToGreen)?p.startToGreen+' days':'–'}</b><br>Start→green</span><span class="metric"><b>${Number.isFinite(p.greenToFirst)?p.greenToFirst+' days':'–'}</b><br>Green→1st pt</span><span class="metric"><b>${p.maxActive} days</b><br>Oldest active</span></div><p class="small"><b>Interpretation:</b> task completion duration is calculated from Start Date to Completion Date. Active tasks are displayed on the Gantt using their current due/start-derived end date where completion is unavailable, and should be read as unresolved work rather than completed duration.</p><div id="projectMini" class="plot"></div><h4>Project task records</h4><div class="tablewrap"><table id="projectTasks"></table></div>`; drawProjectGantt('projectMini',rs); renderTable('projectTasks',taskCols(),rs,300)}
function taskCols(){return [{label:'Project',key:'project'},{label:'Category',key:'category'},{label:'Task',key:'task'},{label:'Task status',key:'taskStatus'},{label:'Start',f:r=>fmtDate(r.startDate),sort:r=>fmtDate(r.startDate)},{label:'Completed',f:r=>fmtDate(r.completionDate),sort:r=>fmtDate(r.completionDate)},{label:'Completion duration',f:r=>Number.isFinite(r.taskDuration)?r.taskDuration+' days':(r.isOpen?'Active':'–'),sort:r=>r.taskDuration??-1},{label:'Active age',f:r=>r.isOpen&&Number.isFinite(r.daysActive)?r.daysActive+' days':'',sort:r=>r.daysActive??-1},{label:'Due',f:r=>fmtDate(r.dueDate),sort:r=>fmtDate(r.dueDate)},{label:'Comment',f:r=>`<span class="small">${esc((r.taskComment||'').slice(0,220))}</span>`}]}
function initTasks(){document.getElementById('taskStatusFilter').innerHTML += [...new Set(rows.map(r=>r.taskStatus))].sort().map(s=>`<option>${esc(s)}</option>`).join(''); document.getElementById('taskCategoryFilter').innerHTML += CATEGORY_RULES.map(x=>x[0]).map(s=>`<option>${esc(s)}</option>`).join(''); let cats=cAgg.slice(0,24).reverse(); plot('categoryDelayPlot',[{type:'bar',orientation:'h',y:barLabels(cats.map(c=>c.category),36),x:cats.map(c=>Math.round(c.meanDelay*10)/10),customdata:cats.map(c=>c.category),text:cats.map(c=>`${c.lateRate}% late · ${c.active} active`),hovertemplate:'%{customdata}<br>Mean completion duration: %{x} days<br>%{text}<extra></extra>',marker:{color:cats.map(c=>c.meanDelay),colorscale:'YlOrRd'}}],{title:'Task categories by mean completion duration',xaxis:{title:'mean completion days'}}); plot('categoryMixPlot',[{type:'bar',orientation:'h',y:barLabels(cats.map(c=>c.category),36),x:cats.map(c=>c.n),name:'all tasks'},{type:'bar',orientation:'h',y:barLabels(cats.map(c=>c.category),36),x:cats.map(c=>c.active),name:'active/pending'}],{title:'Workload by category',barmode:'stack',xaxis:{title:'records'}}); let top=tAgg.slice(0,22).reverse(); plot('taskTypePlot',[{type:'bar',orientation:'h',y:barLabels(top.map(t=>t.task),46),x:top.map(t=>t.bottleneckScore),customdata:top.map(t=>t.task),hovertemplate:'%{customdata}<br>Bottleneck score: %{x}<extra></extra>',marker:{color:'#b45309'}}],{title:'Task names by completion-duration / active-backlog score'}); plot('taskPerfPlot',[{type:'scatter',mode:'markers',x:tAgg.map(t=>t.active),y:tAgg.map(t=>t.meanDuration),text:tAgg.map(t=>t.task),hovertemplate:'%{text}<br>Active records %{x}<br>Mean completion duration %{y:.1f} days<extra></extra>',marker:{size:tAgg.map(t=>Math.max(7,Math.min(30,t.n))),color:tAgg.map(t=>t.active),colorscale:'Viridis',showscale:true,colorbar:{title:'active'}}}],{title:'Task type performance map',xaxis:{title:'active records'},yaxis:{title:'mean completion duration days'}}); ['taskSearch','taskStatusFilter','taskTimingFilter','taskCategoryFilter'].forEach(id=>document.getElementById(id).addEventListener('input',renderTasks)); renderTasks()}
function renderTasks(){let q=document.getElementById('taskSearch').value.toLowerCase(), st=document.getElementById('taskStatusFilter').value, tf=document.getElementById('taskTimingFilter').value, cat=document.getElementById('taskCategoryFilter').value; let data=rows.filter(r=>(!q||(r.task+' '+r.project+' '+r.taskComment+' '+r.category).toLowerCase().includes(q))&&(!st||r.taskStatus===st)&&(!cat||r.category===cat)&&(!tf||(tf==='Active/Pending'?r.taskStatus!=='Complete':r.timing===tf))).sort((a,b)=>(b.isOpen-a.isOpen)||(b.lateDays-a.lateDays)||((b.elapsed||0)-(a.elapsed||0))); renderTable('taskTable',taskCols(),data,1200)}
function initBottlenecks(){let top=cAgg.slice(0,25).reverse(); plot('bottleneckPlot',[{type:'bar',orientation:'h',y:barLabels(top.map(t=>t.category),36),x:top.map(t=>t.bottleneckScore),customdata:top.map(t=>t.category),hovertemplate:'%{customdata}<br>Bottleneck score: %{x}<extra></extra>',marker:{color:'#dc2626'}}],{title:'Categories by bottleneck score'}); let active=rows.filter(r=>r.isOpen).sort((a,b)=>(b.lateDays-a.lateDays)||((b.daysActive||0)-(a.daysActive||0))); let topA=active.slice(0,24).reverse(); plot('overduePlot',[{type:'bar',orientation:'h',y:barLabels(topA.map(r=>r.project+' · '+r.task),58),x:topA.map(r=>r.daysActive||0),marker:{color:topA.map(r=>r.lateDays>0?'#dc2626':(r.daysActive||0)>60?'#b45309':'#2563eb')}}],{title:'Longest-running unresolved tasks',xaxis:{title:'days active'}}); renderTable('bottleneckTable',taskCols(),active,800); renderTable('resourceTable',[{label:'Category',key:'category'},{label:'Records',key:'n'},{label:'Projects',key:'projects'},{label:'Active',key:'active'},{label:'Overdue',key:'overdue'},{label:'>60 days active',key:'over60'},{label:'Projects >60 setup',key:'missedSetupProjects'},{label:'Projects >30 recruit',key:'missedFirstProjects'},{label:'Late rate',f:c=>c.lateRate+'%',sort:c=>c.lateRate},{label:'Mean completion',f:c=>Math.round(c.meanDays*10)/10+' days',sort:c=>c.meanDays},{label:'Resource score',key:'bottleneckScore'}],cAgg,100)}
const OP_THEMES=[
 {name:'Document pack / local information completeness',terms:['local information pack','document pack','hra approval','iras','oid','pis','icf','protocol','delegation log','missing documents'],interpretation:'Repeated delays here usually indicate incomplete or late sponsor document transfer, localising/checking document packs, or rework needed before setup can proceed. This is a good candidate for earlier document triage/checklists and dedicated admin capacity.'},
 {name:'Finance, costing and invoicing',terms:['finance','costing','cost code','invoice','invoicing','reconciliation','setup fees','set-up fees','cpms','soecat'],interpretation:'These records point to costing, finance review, cost-code creation and invoicing as operational pinch-points. Extra finance/R&D office capacity or clearer commercial/non-commercial routing may improve throughput.'},
 {name:'Support department capacity checks',terms:['pharmacy','labs','laboratory','ribs','biospecimen','biobank','imaging','access imaging','drug storage','pharmacy manual'],interpretation:'Delays cluster around specialist support departments. The comments suggest dependency on minimum datasets, manuals, sample/storage details and departmental capacity-and-capability confirmation.'},
 {name:'Governance, risk assessment and approvals',terms:['risk assessment','planning review','clinical director','notification','regulatory','approval','ethics','amendment'],interpretation:'These are internal governance steps. Delays may reflect hand-offs for risk assessment, sign-off, clinical director notification or governance review rather than purely sponsor-side delay.'},
 {name:'Sponsor hand-off / site selected / trust invited',terms:['trust invited','trust selected','site invited','site selected','sponsor email','sponsor requests','information to mft','start set-up'],interpretation:'These comments relate to when the setup clock starts. Bottlenecks here may be poor timestamp quality, unclear sponsor handover, or delayed transfer of complete information needed to begin setup.'},
 {name:'Green light and recruitment activation',terms:['green light','recruitment can commence','siv','site initiation','recruitment plan','retention plan'],interpretation:'These records sit close to setup completion. Delays here may represent final activation steps, SIV scheduling or unresolved prerequisites blocking green light.'},
 {name:'First patient / recruitment delivery',terms:['1st patient','first patient','first eligible patient','consented','delay reasons','patient recruited','non-recruiting'],interpretation:'These tasks map to the 30-day green-light-to-first-consent target. Delays may need study-team recruitment planning support rather than setup-process resource alone.'},
 {name:'Systems / Hive / access build',terms:['hive','ehr','build request','researchcontent','system','database','access','account','login'],interpretation:'These records suggest digital build/access dependencies. If recurrent, a standardised early Hive/EHR request workflow may reduce late activation delays.'},
 {name:'Service support / NHS support costs',terms:['service support','nhs support','lcrn','resource','support costs','director of research delivery'],interpretation:'These comments suggest uncertainty about support costs or service implications. Delays may benefit from earlier escalation and decision ownership.'}
];
function delayedForThemes(){return rows.filter(r=>r.timing==='Late'||r.lateDays>0||r.overTarget>0||(r.isOpen&&Number.isFinite(r.daysActive)&&r.daysActive>30))}
function themeForRecord(r){let text=((r.task||'')+' '+(r.taskComment||'')+' '+(r.category||'')).toLowerCase(); let best=null, score=0; OP_THEMES.forEach(t=>{let s=0; t.terms.forEach(term=>{if(text.includes(term)) s += term.length>12?3:1}); if(s>score){score=s; best=t}}); return best || {name:'Other operational hand-offs',terms:[],interpretation:'Delayed records not captured by the predefined themes. These should be reviewed manually for local process-specific constraints.'}}
function themeAgg(){let delayed=delayedForThemes(), m=new Map(); delayed.forEach(r=>{let t=themeForRecord(r); if(!m.has(t.name)) m.set(t.name,{...t,records:[],projects:new Set(),late:0,active:0,over60:0,totalDelay:0}); let x=m.get(t.name); x.records.push(r); x.projects.add(r.project); if(r.timing==='Late') x.late++; if(r.isOpen) x.active++; if((r.daysActive||0)>60) x.over60++; x.totalDelay += r.overTarget||r.lateDays||0}); return [...m.values()].map(x=>({...x,projectsN:x.projects.size,n:x.records.length,meanElapsed:mean(x.records.map(r=>r.elapsed))||0,meanDelay:x.records.length?x.totalDelay/x.records.length:0,score:Math.round(x.n*2+x.active*3+x.over60*8+x.meanDelay+x.projectsN)})).sort((a,b)=>b.score-a.score)}
function initThemes(){let themes=themeAgg(); let top=themes.slice(0,8); document.getElementById('themeNarrative').innerHTML=top.map(t=>{let examples=t.records.slice().sort((a,b)=>(b.elapsed||0)-(a.elapsed||0)).slice(0,3).map(r=>`<li><b>${esc(r.project)}</b>: ${esc(r.task)} <span class="muted">(${r.elapsed??'–'} d; ${esc(r.taskStatus)})</span><br><span class="small">${esc((r.taskComment||'').slice(0,210))}</span></li>`).join(''); return `<div class="card"><h3>${esc(t.name)}</h3><div class="pillrow"><span class="metric"><b>${t.n}</b><br>Delayed records</span><span class="metric"><b>${t.projectsN}</b><br>Projects</span><span class="metric"><b>${t.active}</b><br>Active</span><span class="metric"><b>${t.over60}</b><br>>60 days active</span><span class="metric"><b>${Math.round(t.meanElapsed*10)/10} days</b><br>Mean elapsed</span></div><p>${esc(t.interpretation)}</p><p class="small"><b>Evidence examples</b></p><ul class="small">${examples}</ul></div>`}).join(''); let rev=[...top].reverse(); plot('themeBurdenPlot',[{type:'bar',orientation:'h',y:barLabels(rev.map(t=>t.name),38),x:rev.map(t=>t.n),name:'delayed records'},{type:'bar',orientation:'h',y:barLabels(rev.map(t=>t.name),38),x:rev.map(t=>t.active),name:'active'}],{title:'Thematic burden among delayed records',barmode:'stack',xaxis:{title:'records'}}); plot('themeDelayPlot',[{type:'bar',orientation:'h',y:barLabels(rev.map(t=>t.name),38),x:rev.map(t=>Math.round(t.meanElapsed*10)/10),marker:{color:rev.map(t=>t.over60>0?'#dc2626':'#b45309')}}],{title:'Mean elapsed/active days by operational theme',xaxis:{title:'days'}}); let delayed=delayedForThemes().map(r=>({...r,theme:themeForRecord(r).name})).sort((a,b)=>(b.elapsed||0)-(a.elapsed||0)); renderTable('themeTable',[{label:'Theme',key:'theme'},{label:'Project',key:'project'},{label:'Category',key:'category'},{label:'Task',key:'task'},{label:'Status',key:'taskStatus'},{label:'Elapsed/active',f:r=>r.elapsed??'',sort:r=>r.elapsed??-1},{label:'Delay',f:r=>r.overTarget?`<span class="badge late">+${r.overTarget} days</span>`:'',sort:r=>r.overTarget||0},{label:'Comment',f:r=>`<span class="small">${esc((r.taskComment||'').slice(0,260))}</span>`}],delayed,1200)}

function projectAggFor(sourceRows){return [...group(sourceRows,'project')].map(([project,rs])=>{let active=rs.filter(r=>r.isOpen), comp=rs.filter(r=>r.taskStatus==='Complete'), late=comp.filter(r=>r.timing==='Late'), over60=active.filter(r=>(r.daysActive||0)>60), over30=active.filter(r=>(r.daysActive||0)>30), elapsed=rs.map(r=>r.elapsed).filter(Number.isFinite), activeAge=active.map(r=>r.daysActive).filter(Number.isFinite), overdue=active.filter(r=>r.lateDays>0); let start=setupStart(rs), end=setupEnd(rs), gl=greenLightRow(rs), fp=firstPatientRow(rs), greenDate=gl?(gl.completionDate||gl.dueDate||null):null, fpDate=fp?(fp.completionDate||fp.dueDate||null):null, setupDays=daysBetween(start,end), startToGreen=daysBetween(start,greenDate), greenToFirst=daysBetween(greenDate,fpDate); let missSetup=Number.isFinite(startToGreen)?startToGreen>60:false, missFirst=Number.isFinite(greenToFirst)?greenToFirst>30:false; let score=overdue.length*7 + over60.length*12 + over30.length*4 + active.reduce((s,r)=>s+(r.overTarget||0),0) + late.length*1.5 + (mean(elapsed)||0)*0.15 + (missSetup?30:0) + (missFirst?20:0); let band=score>140?'Critical':score>60?'High':score>20?'Moderate':'Low'; return {project,projectStatus:rs[0]?.projectStatus||'Unknown',n:rs.length,complete:comp.length,active:active.length,late:late.length,lateRate:pct(late.length,comp.length||rs.length),medianDays:median(elapsed),meanDays:mean(elapsed),maxActive:activeAge.length?Math.max(...activeAge):0,overdue:overdue.length,over30:over30.length,over60:over60.length,setupStart:start,setupEnd:end,setupDays,startToGreen,greenToFirst,missSetup,missFirst,riskScore:Math.round(score),riskBand:band,tasks:rs}}).sort((a,b)=>b.riskScore-a.riskScore)}
function categoryAggFor(sourceRows,sourcePAgg){return [...group(sourceRows,'category')].map(([category,rs])=>{let comp=rs.filter(r=>r.taskStatus==='Complete'), active=rs.filter(r=>r.isOpen), late=comp.filter(r=>r.timing==='Late'), elapsed=rs.map(r=>r.elapsed).filter(Number.isFinite), delay=rs.map(r=>r.overTarget||r.lateDays||0).filter(Number.isFinite), overdue=active.filter(r=>r.lateDays>0), over60=active.filter(r=>(r.daysActive||0)>60), projectSet=new Set(rs.map(r=>r.project)); let missedSetupProjects=[...projectSet].filter(p=>sourcePAgg.find(x=>x.project===p)?.missSetup).length, missedFirstProjects=[...projectSet].filter(p=>sourcePAgg.find(x=>x.project===p)?.missFirst).length; return {category,n:rs.length,projects:projectSet.size,complete:comp.length,active:active.length,late:late.length,lateRate:pct(late.length,comp.length||rs.length),medianDays:median(elapsed),meanDays:mean(elapsed),medianDelay:median(delay)||0,meanDelay:mean(delay)||0,overdue:overdue.length,over60:over60.length,missedSetupProjects,missedFirstProjects,bottleneckScore:Math.round((mean(delay)||0)*3+late.length+overdue.length*8+over60.length*12+active.length*.5+missedSetupProjects*4+missedFirstProjects*3),rows:rs}}).sort((a,b)=>b.bottleneckScore-a.bottleneckScore)}
function taskDateForReport(r){return r.completionDate||r.dueDate||r.startDate||r.createdDate||lastDateOf(r)}
function reportDateExtent(){let ds=rows.map(taskDateForReport).filter(Boolean).sort((a,b)=>a-b); return {min:ds[0]||null,max:ds[ds.length-1]||null}}
function initReport(){let ex=reportDateExtent(); if(ex.min&&!document.getElementById('reportFrom').value) document.getElementById('reportFrom').value=fmtDate(ex.min); if(ex.max&&!document.getElementById('reportTo').value) document.getElementById('reportTo').value=fmtDate(ex.max); generateReport()}
function reportRows(){let from=excelDate(document.getElementById('reportFrom').value), to=excelDate(document.getElementById('reportTo').value); if(to) to=new Date(to.getTime()+MS_DAY-1); return rows.filter(r=>{let d=taskDateForReport(r); return d && (!from||d>=from) && (!to||d<=to)})}
function plain(s){return esc(String(s??''))}
function reportTable(cols,data,limit=20){return `<table class="report-table"><thead><tr>${cols.map(c=>`<th style="width:${c.w||''}">${esc(c.label)}</th>`).join('')}</tr></thead><tbody>${data.slice(0,limit).map(r=>`<tr>${cols.map(c=>`<td class="${c.num?'num':''}">${c.f?c.f(r):plain(r[c.key])}</td>`).join('')}</tr>`).join('')}</tbody></table>`}
function reportThemeAgg(sourceRows){let delayed=sourceRows.filter(r=>r.timing==='Late'||r.lateDays>0||r.overTarget>0||(r.isOpen&&Number.isFinite(r.daysActive)&&r.daysActive>30)), m=new Map(); delayed.forEach(r=>{let t=themeForRecord(r); if(!m.has(t.name))m.set(t.name,{...t,records:[],projects:new Set(),active:0,over60:0,totalDelay:0}); let x=m.get(t.name); x.records.push(r); x.projects.add(r.project); if(r.isOpen)x.active++; if((r.daysActive||0)>60)x.over60++; x.totalDelay+=r.overTarget||r.lateDays||0}); return [...m.values()].map(x=>({...x,n:x.records.length,projectsN:x.projects.size,meanElapsed:mean(x.records.map(r=>r.elapsed))||0,meanDelay:x.records.length?x.totalDelay/x.records.length:0,score:Math.round(x.n*2+x.active*3+x.over60*8+x.meanDelay+x.projectsN)})).sort((a,b)=>b.score-a.score)}
function reportDomainNarrative(c,sourceRows){let active=c.rows.filter(r=>r.isOpen).sort((a,b)=>(b.elapsed||0)-(a.elapsed||0)); let topProjects=[...group(c.rows,'project')].map(([p,rs])=>[p,rs.length]).sort((a,b)=>b[1]-a[1]).slice(0,3).map(x=>x[0]).join(', '); let example=active[0]||c.rows.slice().sort((a,b)=>(b.overTarget||0)-(a.overTarget||0))[0]; let issue=c.over60?`${c.over60} active records are already beyond 60 days`:c.overdue?`${c.overdue} active records are overdue`:`${c.lateRate}% of completed records were late`; return `${c.category} affects ${c.projects} projects in this period, especially ${topProjects||'no dominant project cluster'}. ${issue}. ${example?`The most useful immediate review is ${example.project}: ${example.task}, because it is ${example.elapsed??'not'} days old/elapsed and sits in the ${example.taskStatus} state.`:''}`}
function generateReport(){let out=document.getElementById('reportOutput'), status=document.getElementById('reportStatus'); let scoped=reportRows(); let pa=projectAggFor(scoped), ca=categoryAggFor(scoped,pa), themes=reportThemeAgg(scoped); let complete=scoped.filter(r=>r.taskStatus==='Complete'), active=scoped.filter(r=>r.isOpen), late=complete.filter(r=>r.timing==='Late'), from=document.getElementById('reportFrom').value, to=document.getElementById('reportTo').value; let setupVals=pa.map(p=>p.startToGreen).filter(Number.isFinite), recruitVals=pa.map(p=>p.greenToFirst).filter(Number.isFinite), missedSetup=pa.filter(p=>p.missSetup), missedFirst=pa.filter(p=>p.missFirst); let monthGroups=[...group(complete,r=>r.completionDate?fmtDate(r.completionDate).slice(0,7):'Unknown')].filter(x=>x[0]!=='Unknown').sort(); let latestMonths=monthGroups.slice(-3); let trendText=latestMonths.length?`In the latest observed months (${latestMonths.map(x=>x[0]).join(', ')}), completed-task volume was ${latestMonths.map(x=>x[1].length).join(' / ')} records, with late completions ${latestMonths.map(x=>x[1].filter(r=>r.timing==='Late').length).join(' / ')} respectively.`:'There are insufficient dated completions in the selected window to describe a completion trend.'; let topActive=active.slice().sort((a,b)=>(b.lateDays-a.lateDays)||((b.elapsed||0)-(a.elapsed||0))).slice(0,18); let pages=`
<div class="report-page"><div class="report-title"><div><h2>R-PEAK setup and bottleneck report</h2><p class="small">Time-bounded operational report for ${plain(from)} to ${plain(to)}.</p></div><div class="report-meta">Generated ${new Date().toLocaleString()}<br>${scoped.length} records · ${pa.length} projects</div></div><div class="report-kpis"><div class="report-kpi"><b>${pa.length}</b><br>Projects</div><div class="report-kpi"><b>${median(setupVals)??'–'} days</b><br>Median start→green</div><div class="report-kpi"><b>${median(recruitVals)??'–'} days</b><br>Median green→1st patient</div><div class="report-kpi"><b>${pct(late.length,complete.length)}%</b><br>Completed late</div></div><div class="report-section"><h3>Methodology and limits</h3><p>This report uses the currently loaded dashboard dataset and only includes records with a usable created, start, due or completion date inside the selected window. Project setup is estimated from task timestamps because the export does not contain a fully validated HRA/site-initiation clock for every study. Start→green light uses the first task/start timestamp as a pragmatic proxy for HRA approval or sponsor information transfer, and the green-light task completion/due date as the setup endpoint. Green→1st patient uses the green-light date and first-patient/first-consent task date where present.</p><p>The 150-day clinical trial target is represented operationally by the 60-day setup/open-to-recruit component and the 30-day first-patient component. Bottleneck and resource scores are prioritisation signals combining active backlog, overdue/over-target delay, records active over 60 days, delayed-task volume, and contribution to projects missing the 60/30 components. They are not formal audited performance measures.</p><div class="report-note"><b>Time constraint:</b> all plots, tables and narrative below are restricted to ${plain(from)}–${plain(to)}. Changing the date range and regenerating the report will change the denominators and trends.</div></div></div>
<div class="report-page"><div class="report-section"><h3>Performance over time</h3><p>${trendText} This view is intended to show whether throughput and late completions are moving together over time, rather than only giving a static backlog count.</p><div id="reportTrendPlot" class="report-plot"></div><h3>150-day clinical trial target components</h3><p>${missedSetup.length}/${setupVals.length} projects with a measurable start→green-light interval exceed 60 days. ${missedFirst.length}/${recruitVals.length} projects with a measurable green→first-patient interval exceed 30 days. Projects in the upper tail should be reviewed for whether delay is due to document hand-off, support-department confirmation, finance/costing, SIV/activation, or recruitment delivery after green light.</p><div id="reportSetupPlot" class="report-plot"></div></div></div>
<div class="report-page"><div class="report-section"><h3>Highest-risk projects</h3><p>These projects combine high active backlog, overdue/over-target work, old unresolved records and missed setup/recruitment target components. The table is deliberately narrow so that it fits A4 output.</p>${reportTable([{label:'Project',key:'project',w:'18%'},{label:'Status',key:'projectStatus',w:'15%'},{label:'Risk',key:'riskBand',w:'10%'},{label:'Tasks',key:'n',num:true,w:'7%'},{label:'Active',key:'active',num:true,w:'7%'},{label:'Start→green',f:p=>Number.isFinite(p.startToGreen)?p.startToGreen+' days':'–',num:true,w:'10%'},{label:'Green→1st',f:p=>Number.isFinite(p.greenToFirst)?p.greenToFirst+' days':'–',num:true,w:'10%'},{label:'Oldest active',f:p=>p.maxActive+' days',num:true,w:'10%'},{label:'Score',key:'riskScore',num:true,w:'8%'}],pa.slice(0,18),18)}</div></div>
<div class="report-page"><div class="report-section"><h3>Task domains and operational interpretation</h3><p>The domains below are ranked by resource/bottleneck score in the selected window. Narrative statements are generated from the actual projects, task states and comments in each domain, so they should be read as prompts for operational review rather than causal proof.</p><div id="reportCategoryPlot" class="report-plot"></div>${ca.slice(0,8).map(c=>`<h3>${plain(c.category)}</h3><p>${plain(reportDomainNarrative(c,scoped))}</p>`).join('')}</div></div>
<div class="report-page"><div class="report-section"><h3>Resource-focus table</h3>${reportTable([{label:'Domain',key:'category',w:'22%'},{label:'Records',key:'n',num:true,w:'8%'},{label:'Projects',key:'projects',num:true,w:'8%'},{label:'Active',key:'active',num:true,w:'8%'},{label:'Overdue',key:'overdue',num:true,w:'8%'},{label:'>60 days active',key:'over60',num:true,w:'10%'},{label:'Late rate',f:c=>c.lateRate+'%',num:true,w:'8%'},{label:'Mean delay',f:c=>Math.round(c.meanDelay*10)/10+' days',num:true,w:'10%'},{label:'Score',key:'bottleneckScore',num:true,w:'8%'}],ca,24)}</div></div>
<div class="report-page"><div class="report-section"><h3>Thematic delayed-task analysis</h3><p>The chart and examples focus on delayed, overdue, over-target and long-active records. This helps distinguish whether the selected period is dominated by setup administration, finance, support departments, governance, activation, or first-patient delivery.</p><div id="reportThemePlot" class="report-plot"></div>${themes.slice(0,6).map(t=>{let ex=t.records.slice().sort((a,b)=>(b.elapsed||0)-(a.elapsed||0))[0]; return `<h3>${plain(t.name)}</h3><p>${plain(t.interpretation)} In this period it appears in ${t.n} delayed records across ${t.projectsN} projects; ${t.active} remain active and ${t.over60} are beyond 60 days active.${ex?` Example: ${ex.project} — ${ex.task} (${ex.elapsed??'–'} days, ${ex.taskStatus}).`:''}</p>`}).join('')}</div></div>
<div class="report-page"><div class="report-section"><h3>Priority active/pending records</h3><p>These are the records most likely to need near-term operational action because they are still open and/or longest-running. Comments are truncated for A4 fit; use the dashboard tables for full text.</p>${reportTable([{label:'Project',key:'project',w:'14%'},{label:'Domain',key:'category',w:'18%'},{label:'Task',key:'task',w:'24%'},{label:'Status',key:'taskStatus',w:'10%'},{label:'Elapsed',f:r=>(r.elapsed??'–')+' days',num:true,w:'8%'},{label:'Delay',f:r=>r.overTarget?`+${r.overTarget} days`:'',num:true,w:'8%'},{label:'Comment',f:r=>plain((r.taskComment||'').slice(0,150)),w:'18%'}],topActive,18)}</div></div>`; out.innerHTML=pages; status.textContent=`Report generated for ${scoped.length} records across ${pa.length} projects.`; setTimeout(()=>drawReportPlots(monthGroups,pa,ca,themes),80)}
function drawReportPlots(monthGroups,pa,ca,themes){plot('reportTrendPlot',[{type:'scatter',mode:'lines+markers',x:monthGroups.map(x=>x[0]),y:monthGroups.map(x=>x[1].length),name:'completed'},{type:'scatter',mode:'lines+markers',x:monthGroups.map(x=>x[0]),y:monthGroups.map(x=>x[1].filter(r=>r.timing==='Late').length),name:'late'}],{title:'Completed and late completed records by month',margin:{l:55,r:20,t:50,b:60},yaxis:{title:'records'}}); let setup=pa.filter(p=>Number.isFinite(p.startToGreen)).sort((a,b)=>b.startToGreen-a.startToGreen).slice(0,18).reverse(); plot('reportSetupPlot',[{type:'bar',orientation:'h',y:setup.map(p=>p.project),x:setup.map(p=>p.startToGreen),marker:{color:setup.map(p=>p.startToGreen>60?'#dc2626':'#15803d')}}],{title:'Projects with longest start→green-light intervals',margin:{l:130,r:20,t:50,b:55},xaxis:{title:'days'},shapes:[{type:'line',x0:60,x1:60,y0:-0.5,y1:setup.length-0.5,line:{color:'#991b1b',dash:'dash'}}]}); let cats=ca.slice(0,14).reverse(); plot('reportCategoryPlot',[{type:'bar',orientation:'h',y:cats.map(c=>c.category),x:cats.map(c=>c.bottleneckScore),marker:{color:'#b45309'}}],{title:'Domains by resource/bottleneck score',margin:{l:150,r:20,t:50,b:55},xaxis:{title:'score'}}); let th=themes.slice(0,10).reverse(); plot('reportThemePlot',[{type:'bar',orientation:'h',y:th.map(t=>t.name),x:th.map(t=>t.n),name:'delayed records'},{type:'bar',orientation:'h',y:th.map(t=>t.name),x:th.map(t=>t.active),name:'active'}],{title:'Delayed-task themes',barmode:'stack',margin:{l:170,r:20,t:50,b:55},xaxis:{title:'records'}})}
async function waitForReportPlots(){let ids=['reportTrendPlot','reportSetupPlot','reportCategoryPlot','reportThemePlot']; await new Promise(r=>setTimeout(r,350)); for(let id of ids){let el=document.getElementById(id); if(el && el._promises && el._promises.length){try{await Promise.all(el._promises)}catch(e){}}}}
async function downloadReportPdf(){let status=document.getElementById('reportStatus'); try{if(!document.getElementById('reportOutput').innerHTML.trim()) generateReport(); if(status) status.textContent='Preparing PDF…'; await waitForReportPlots(); if(!window.html2canvas || !window.jspdf){throw new Error('PDF export libraries are still loading. Please wait a few seconds and try again.')} let pages=[...document.querySelectorAll('#reportOutput .report-page')]; if(!pages.length) throw new Error('No report pages found. Generate the report first.'); const {jsPDF}=window.jspdf; let pdf=new jsPDF({orientation:'portrait',unit:'mm',format:'a4',compress:true}); let pageW=210,pageH=297, margin=8, usableW=pageW-margin*2, footerY=291; for(let i=0;i<pages.length;i++){if(status) status.textContent=`Rendering PDF page ${i+1} of ${pages.length}…`; let page=pages[i]; let oldStyle=page.getAttribute('style')||''; page.style.width='1040px'; page.style.maxWidth='1040px'; page.style.border='0'; page.style.borderRadius='0'; let canvas=await html2canvas(page,{scale:1.6,backgroundColor:'#ffffff',useCORS:true,logging:false,windowWidth:1200}); page.setAttribute('style',oldStyle); if(i>0) pdf.addPage('a4','portrait'); let imgData=canvas.toDataURL('image/jpeg',0.92); let imgH=canvas.height*usableW/canvas.width; let maxImgH=pageH-margin*2-8; if(imgH<=maxImgH){pdf.addImage(imgData,'JPEG',margin,margin,usableW,imgH)}else{pdf.addImage(imgData,'JPEG',margin,margin,usableW,maxImgH)} pdf.setFontSize(8); pdf.setTextColor(110); pdf.text(`Page ${i+1} of ${pages.length}`,pageW-margin,footerY,{align:'right'});} let from=document.getElementById('reportFrom')?.value||'report', to=document.getElementById('reportTo')?.value||''; pdf.save(`rpeak-report-${from}${to?'-to-'+to:''}.pdf`); if(status) status.textContent=`PDF downloaded (${pages.length} pages).`;}catch(e){console.error(e); if(status) status.textContent=`PDF export failed: ${e.message}. Try the Print fallback button.`;}}
function printReportPdf(){if(!document.getElementById('reportOutput').innerHTML.trim()) generateReport(); document.querySelectorAll('.panel').forEach(x=>x.classList.remove('active')); document.getElementById('report').classList.add('active'); let status=document.getElementById('reportStatus'); if(status) status.textContent='Opening browser print dialog… if nothing appears, use Download PDF.'; setTimeout(()=>window.print(),450)}

function initRaw(){document.getElementById('rawSearch').addEventListener('input',renderRaw); document.getElementById('uploadFile')?.addEventListener('change',handleUpload); let status=document.getElementById('uploadStatus'); if(status){let meta=currentDataMeta(); status.innerHTML=meta.uploaded?`Using uploaded data: <b>${esc(meta.name)}</b> (${RAW.length} rows). <span class="muted">${esc(meta.note||'')}</span>`:`Using bundled source data (${RAW.length} rows).`} renderRaw()}
function renderRaw(){let q=document.getElementById('rawSearch').value.toLowerCase(); let data=rows.filter(r=>!q||Object.values(r).join(' ').toLowerCase().includes(q)); let cols=['Project Code','Project Status','Task Name','Target Days to complete','Date Created','Start Date','Due Date','Completion Date','On time or Late','Days to completion','Days active (if not complete)','Task Status'].map(c=>({label:c,f:r=>esc(r[c]||'')})); renderTable('rawTable',cols,data,1500)}
document.querySelectorAll('.tabs .tab[data-tab]').forEach(b=>b.onclick=()=>{document.querySelectorAll('.tabs .tab[data-tab],.panel').forEach(x=>x.classList.remove('active')); b.classList.add('active'); document.getElementById(b.dataset.tab).classList.add('active'); if(b.dataset.tab==='themes') initThemes(); if(b.dataset.tab==='report') initReport(); setTimeout(()=>window.dispatchEvent(new Event('resize')),50)});
initOverview(); initProjects(); initTasks(); initBottlenecks(); initThemes(); initRaw(); initReport();
